target_langs = ['fr', 'es', 'de', 'zh', 'ja', 'ru']
current_lang = None
new_lines = []
stats = {lang: {'nav_company_added': False, 'block_inserted': False, 'keys_added': 0} for lang in target_langs}

for i, line in enumerate(lines):
    # Detect language section start
    lang_match = re.match(r'\s+(en|ar|fr|es|de|zh|ja|ru):\s*\{', line)
    if lang_match:
        current_lang = lang_match.group(1)

    # Detect language section end (closing brace with proper indentation)
    if current_lang and re.match(r'^  \},', line):
        current_lang = None

    # Process nav.about line for target languages
    if current_lang in target_langs and 'nav.about' in line and 'nav.company' not in line:
        line = line.rstrip('\n').rstrip('\r')
        if line.endswith(','):
            line = line + ' ' + nav_company[current_lang]
        else:
            line = line + ', ' + nav_company[current_lang]
        line = line + '\n'
        stats[current_lang]['nav_company_added'] = True

    new_lines.append(line)

    # After tutorials.expert line for target languages, insert the block
    if current_lang in target_langs and "'tutorials.expert'" in line:
        block = translation_blocks[current_lang]
        # Count keys in the block
        key_count = len(re.findall(r"'[\w.]+':\s*'", block))
        new_lines.append(block + '\n')
        stats[current_lang]['block_inserted'] = True
        stats[current_lang]['keys_added'] = key_count

# Write to temp file since original may have restricted permissions
outpath = '/home/z/my-project/src/lib/i18n_new.tsx'
with open(outpath, 'w', encoding='utf-8') as f:
    f.writelines(new_lines)
print(f"\n  Written to: {outpath}")
print(f"  (rename/replace original manually if needed)")

# Print summary
print("=" * 60)
print("TRANSLATION INSERTION SUMMARY")
print("=" * 60)
total_keys = 0
for lang in target_langs:
    s = stats[lang]
    print(f"\n  {lang.upper()}:")
    print(f"    nav.company added to nav.about line: {s['nav_company_added']}")
    print(f"    Translation block inserted:          {s['block_inserted']}")
    print(f"    Keys in block:                        {s['keys_added']}")
    total_keys += s['keys_added'] + (1 if s['nav_company_added'] else 0)

print(f"\n  TOTAL keys added across all languages: {total_keys}")
print("=" * 60)
